// Learn: Choose functional interfaces by input and output.
import java.util.function.Consumer;
import java.util.function.Function;
import java.util.function.Predicate;

Function<String, Integer> length = String::length;
// Predicate returns true or false for one value.
Predicate<String> isLong = text -> length.apply(text) > 8;
Consumer<String> printer = text -> System.out.println(text.trim());
